import React from 'react';
import styles from './stepper.module.css';
import Step from './step';

interface StepperProps {
  active: string;
}

const Stepper: React.FC<StepperProps> = ({ active }) => {
  return (
    <div className={styles.stepper}>
      <Step to="/cart" text="Cart" className={`${styles.stepper_item} ${active === "Cart" ? styles.stepper_active : ""}`} />
      <Step to="/checkout/details" text="Details" className={`${styles.stepper_item} ${active === "Details" ? styles.stepper_active : ""}`} />
      <Step to="/checkout/shipping" text="Shipping" className={`${styles.stepper_item} ${active === "Shipping" ? styles.stepper_active : ""}`} />
      <Step to="/checkout/payment" text="Payment" className={`${styles.stepper_item} ${active === "Payment" ? styles.stepper_active : ""}`} />
    </div>
  );
}

export default Stepper;
